import (
	"math/bits"
)

type Fenw struct {
	n    int
	tree []int
}

func NewFenw(n int) *Fenw {
	return &Fenw{n: n, tree: make([]int, n+1)}
}

func (f *Fenw) Update(index int, delta int) {
	i := index + 1
	for i <= f.n {
		f.tree[i] += delta
		i += i & -i
	}
}

func (f *Fenw) Query(index int) int {
	i := index + 1
	s := 0
	for i > 0 {
		s += f.tree[i]
		i -= i & -i
	}
	return s
}

func (f *Fenw) QueryRange(l, r int) int {
	if l > r {
		return 0
	}
	res := f.Query(r)
	if l > 0 {
		res -= f.Query(l - 1)
	}
	return res
}

func solve(nums []int64, queries [][]int64) []int64 {
	dp := make([]int, 61)
	dp[1] = 0
	for i := 2; i <= 60; i++ {
		cnt := bits.OnesCount64(uint64(i))
		dp[i] = dp[cnt] + 1
	}

	depth := func(x int64) int {
		if x <= 60 {
			return dp[int(x)]
		}
		cnt := bits.OnesCount64(uint64(x))
		return 1 + dp[cnt]
	}

	n := len(nums)
	depths := make([]int, n)
	fenw := [6]*Fenw{}
	for i := 0; i < 6; i++ {
		fenw[i] = NewFenw(n)
	}

	for i, num := range nums {
		d := depth(num)
		depths[i] = d
		if d < 6 {
			fenw[d].Update(i, 1)
		}
	}

	ans := []int64{}
	for _, q := range queries {
		qt := q[0]
		if qt == 1 {
			l := int(q[1])
			r := int(q[2])
			k := int(q[3])
			var res int
			if k < 0 || k >= 6 {
				res = 0
			} else {
				res = fenw[k].QueryRange(l, r)
			}
			ans = append(ans, int64(res))
		} else if qt == 2 {
			idx := int(q[1])
			val := q[2]
			old_d := depths[idx]
			new_d := depth(val)
			if old_d < 6 {
				fenw[old_d].Update(idx, -1)
			}
			if new_d < 6 {
				fenw[new_d].Update(idx, 1)
			}
			depths[idx] = new_d
			nums[idx] = val
		}
	}
	return ans
}
