import (
    "math/bits"
)

func solve(nums []int64, queries [][]int64) []int64 {
    precomputedTable := make([]int, 61)
    for i := 1; i <= 60; i++ {
        if i == 1 {
            precomputedTable[i] = 0
        } else {
            pop := bits.OnesCount64(uint64(i))
            precomputedTable[i] = 1 + precomputedTable[pop]
        }
    }

    n := len(nums)
    trees := make([]*Fenw, 6)
    for i := 0; i < 6; i++ {
        trees[i] = newFenw(n)
    }

    depthArr := make([]int, n)
    for i, x := range nums {
        d := computeDepth(x, precomputedTable)
        depthArr[i] = d
        if d >= 0 && d <= 5 {
            trees[d].update(i, 1)
        }
    }

    answers := []int64{}
    for _, q := range queries {
        if q[0] == 1 {
            l, r, k := q[1], q[2], q[3]
            if k < 0 || k > 5 {
                answers = append(answers, 0)
            } else {
                res := trees[k].query(int(l), int(r))
                answers = append(answers, res)
            }
        } else if q[0] == 2 {
            idx, val := q[1], q[2]
            idxInt := int(idx)
            old_d := depthArr[idxInt]
            if old_d >= 0 && old_d <= 5 {
                trees[old_d].update(idxInt, -1)
            }
            new_d := computeDepth(val, precomputedTable)
            depthArr[idxInt] = new_d
            if new_d >= 0 && new_d <= 5 {
                trees[new_d].update(idxInt, 1)
            }
        }
    }
    return answers
}

func computeDepth(x int64, precomputedTable []int) int {
    steps := 0
    cur := x
    for cur > 60 {
        cur = int64(bits.OnesCount64(uint64(cur)))
        steps++
    }
    return steps + precomputedTable[cur]
}

type Fenw struct {
    tree []int64
}

func newFenw(n int) *Fenw {
    return &Fenw{
        tree: make([]int64, n),
    }
}

func (f *Fenw) update(i int, delta int64) {
    for j := i; j < len(f.tree); j = j | (j+1) {
        f.tree[j] += delta
    }
}

func (f *Fenw) prefix(i int) int64 {
    if i < 0 {
        return 0
    }
    res := int64(0)
    for j := i; j >= 0; j = (j & (j+1)) - 1 {
        res += f.tree[j]
        if j == 0 {
            break
        }
    }
    return res
}

func (f *Fenw) query(l, r int) int64 {
    if l > r {
        return 0
    }
    return f.prefix(r) - f.prefix(l-1)
}
