```go
import (
	"math/bits"
)

func solve(nums []int64, queries [][]int64) []int64 {
	n := len(nums)
	depthCache := make(map[int64]int)

	var getDepth func(x int64) int
	getDepth = func(x int64) int {
		if x == 1 {
			return 0
		}
		if d, ok := depthCache[x]; ok {
			return d
		}
		pc := bits.OnesCount64(uint64(x))
		d := getDepth(int64(pc))
		depthCache[x] = d + 1
		return d + 1
	}

	type Fenw struct {
		tree []int64
		n    int
	}

	NewFenw := func(n int) *Fenw {
		return &Fenw{
			tree: make([]int64, n+1),
			n:    n,
		}
	}

	updateFenw := func(f *Fenw, i int, delta int64) {
		idx := i + 1
		for idx <= f.n {
			f.tree[idx] += delta
			idx += idx & -idx
		}
	}

	queryFenw := func(f *Fenw, i int) int64 {
		s := int64(0)
		idx := i + 1
		for idx > 0 {
			s += f.tree[idx]
			idx -= idx & -idx
		}
		return s
	}

	rangeQueryFenw := func(f *Fenw, l, r int) int64 {
		if l > r {
			return 0
		}
		if l == 0 {
			return queryFenw(f, r)
		}
		return queryFenw(f, r) - queryFenw(f, l-1)
	}

	fenw := make([]*Fenw, 6)
	for i := 0; i < 6; i++ {
		fenw[i] = NewFenw(n)
	}

	curVal := make([]int64, n)
	copy(curVal, nums)
	curDepth := make([]int, n)

	for i := 0; i < n; i++ {
		d := getDepth(nums[i])
		curDepth[i] = d
		if d >= 0 && d < 6 {
			updateFenw(fenw[d], i, 1)
		}
	}

	ans := []int64{}
	for _, q := range queries {
		if q[0] == 1 {
			l := int(q[1])
			r := int(q[2])
			k := int(q[3])
			if k >= 0 && k < 6 {
				res := rangeQueryFenw(fenw[k], l, r)
				ans = append(ans, res)
			} else {
				ans = append(ans, 0)
			}
		} else if q[0] == 2 {
			idx := int(q[1])
			val := q[2]
			oldDepth := curDepth[idx]
			newDepth := getDepth(val)
			if oldDepth >= 0 && oldDepth < 6 {
				updateFenw(fenw[oldDepth], idx, -1)
			}
			if newDepth >= 0 && newDepth < 6 {
				updateFenw(fenw[newDepth], idx, 1)
			}
			curVal[idx] = val
			curDepth[idx] = newDepth
		}
	}
	return ans
}
```

